How-To-Repeat: 
the test program (test.c) follows;
it was compiled with 
	cc test.c -o test -lc_r

#define _THREAD_SAFE
#define DO_YIELD
#define DO_YIELD2
#include <pthread.h>
#include <stdlib.h>
#include <stdio.h>

void *writer( void *arg )
{
	int i = 0;
	int j;

	for (;; i++) 
		switch (i%7) {
		case 0:	puts( "One" );
			break;
		case 1:	puts( "Two" );
			break;
		case 2:	for (j=0; j<10000000;)
				j++;
			puts( "Three" );
			break;
		case 3:	puts( "Four" );
			break;
		case 4:	puts( "Five" );
			break;
		case 5:	puts( "Six" );
			break;
		case 6:	puts( "Seven" );
#ifdef DO_YIELD
			pthread_yield();
			puts( "Yield in writer returned" );
#endif
			break;
		}

	return NULL;
}

void *looper( void *arg )
{
	long int i = 0;

	for (;;) {
		if (i==10000000) {
			puts( "Yielding" );
#ifdef DO_YIELD2
			pthread_yield();
#endif
			puts( "Yield returned" );
			i = 0;
		}
		else 
			i++;
	}

	return NULL;
}

int main (void)
{

	pthread_t	printer, cpu_hog;
	void 		*result;

	pthread_create( &printer, pthread_attr_default, writer, "first" );
 	pthread_create( &cpu_hog, pthread_attr_default, looper, "second" ); 

	pthread_join( printer, &result );

	return 0;
}
